{
  "name": "Charity Management System",
  "description": "A streamlined digital replacement for paper records in charitable organizations, focused on managing branches, staff, and beneficiaries with role-based access control and an audit trail."
}

export enum Role {
  ADMIN = 'Admin',
  MANAGER = 'Manager',
  STAFF = 'Staff'
}

export enum BeneficiaryStatus {
  ACTIVE = 'نشط',
  SUSPENDED = 'موقوف'
}

export enum BeneficiaryType {
  INDIVIDUAL = 'فرد',
  FAMILY_HEAD = 'رب أسرة',
  FAMILY_MEMBER = 'فرد أسرة'
}

export interface Branch {
  id: string;
  name: string;
  location: string;
  createdAt: string;
}

export interface User {
  id: string;
  name: string;
  username: string;
  password?: string;
  role: Role;
  branchId: string; // Linked to a branch
}

export interface Beneficiary {
  id: string;
  name: string;
  nationalId: string;
  phone: string;
  address: string;
  branchId: string;
  status: BeneficiaryStatus;
  type: BeneficiaryType;
  familyId?: string; // If part of a family
  createdAt: string;
}

export interface Family {
  id: string;
  name: string;
  headId: string;
  branchId: string;
  membersCount: number;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  action: string;
  entityType: string;
  entityId: string;
  timestamp: string;
}

import { Role, Branch, User, Beneficiary, BeneficiaryStatus, BeneficiaryType, AuditLog, Family } from './types';

// Initial Mock Data
const INITIAL_BRANCHES: Branch[] = [
  { id: 'b1', name: 'الفرع الرئيسي - القاهرة', location: 'القاهرة، مدينة نصر', createdAt: new Date().toISOString() },
  { id: 'b2', name: 'فرع الجيزة', location: 'الجيزة، الدقي', createdAt: new Date().toISOString() },
];

const INITIAL_USERS: User[] = [
  { id: 'u1', name: 'أحمد المسؤول', username: 'admin', password: '123', role: Role.ADMIN, branchId: 'b1' },
  { id: 'u2', name: 'محمد مدير الجيزة', username: 'manager', password: '123', role: Role.MANAGER, branchId: 'b2' },
  { id: 'u3', name: 'سارة موظفة القاهرة', username: 'staff', password: '123', role: Role.STAFF, branchId: 'b1' },
];

const INITIAL_BENEFICIARIES: Beneficiary[] = [
  { 
    id: 'ben1', 
    name: 'محمود عبد الله', 
    nationalId: '12345678901234', 
    phone: '01011223344', 
    address: 'شارع 10، المعادي', 
    branchId: 'b1', 
    status: BeneficiaryStatus.ACTIVE, 
    type: BeneficiaryType.INDIVIDUAL, 
    createdAt: new Date().toISOString() 
  },
];

// Helper to interact with Local Storage
const getStorageItem = <T,>(key: string, defaultValue: T): T => {
  const item = localStorage.getItem(key);
  return item ? JSON.parse(item) : defaultValue;
};

const setStorageItem = (key: string, value: any) => {
  localStorage.setItem(key, JSON.stringify(value));
};

export const useStore = () => {
  const branches = getStorageItem<Branch[]>('branches', INITIAL_BRANCHES);
  const users = getStorageItem<User[]>('users', INITIAL_USERS);
  const beneficiaries = getStorageItem<Beneficiary[]>('beneficiaries', INITIAL_BENEFICIARIES);
  const families = getStorageItem<Family[]>('families', []);
  const logs = getStorageItem<AuditLog[]>('audit_logs', []);

  const saveBranches = (data: Branch[]) => setStorageItem('branches', data);
  const saveUsers = (data: User[]) => setStorageItem('users', data);
  const saveBeneficiaries = (data: Beneficiary[]) => setStorageItem('beneficiaries', data);
  const saveFamilies = (data: Family[]) => setStorageItem('families', data);
  const saveLogs = (data: AuditLog[]) => setStorageItem('audit_logs', data);

  const addLog = (user: User, action: string, entityType: string, entityId: string) => {
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      action,
      entityType,
      entityId,
      timestamp: new Date().toISOString()
    };
    saveLogs([newLog, ...logs]);
  };

  return {
    branches, saveBranches,
    users, saveUsers,
    beneficiaries, saveBeneficiaries,
    families, saveFamilies,
    logs, addLog
  };
};

import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Users, 
  Building2, 
  UserPlus, 
  FileText, 
  History, 
  LogOut, 
  UserCircle 
