    { to: '/beneficiaries', icon: <Users size={20} />, label: 'المستفيدين' },
    ...(isAdmin ? [
      { to: '/branches', icon: <Building2 size={20} />, label: 'الفروع' },
      { to: '/users', icon: <UserPlus size={20} />, label: 'المستخدمين' },
    ] : []),
    { to: '/logs', icon: <History size={20} />, label: 'سجل التعديلات' },
  ];

  return (
    <div className="min-h-screen flex bg-gray-50 text-gray-800">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-l border-gray-200 shadow-sm flex flex-col fixed inset-y-0 right-0 z-50">
        <div className="p-6 border-b border-gray-100 flex items-center gap-3">
          <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">
            ج
          </div>
          <span className="font-bold text-lg text-emerald-800">نظام الجمعية</span>
        </div>

        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          {navItems.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              className={({ isActive }) =>
                `flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                  isActive
                    ? 'bg-emerald-50 text-emerald-700 font-semibold'
                    : 'text-gray-600 hover:bg-gray-100'
                }`
              }
            >
              {item.icon}
              <span>{item.label}</span>
            </NavLink>
          ))}
        </nav>

        <div className="p-4 border-t border-gray-100">
          <button
            onClick={onLogout}
            className="flex items-center gap-3 px-4 py-3 w-full rounded-lg text-red-600 hover:bg-red-50 transition-colors"
          >
            <LogOut size={20} />
            <span>تسجيل الخروج</span>
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 mr-64 flex flex-col">
        {/* Top Header */}
        <header className="h-16 bg-white border-b border-gray-200 px-8 flex items-center justify-between sticky top-0 z-40">
          <h2 className="text-xl font-bold text-gray-700">الفرع: {user.branchId}</h2>
          <div className="flex items-center gap-4">
            <div className="text-left">
              <p className="font-semibold text-sm">{user.name}</p>
              <p className="text-xs text-gray-500 uppercase">{user.role}</p>
            </div>
            <div className="w-10 h-10 bg-gray-200 rounded-full flex items-center justify-center text-gray-500">
              <UserCircle size={28} />
            </div>
          </div>
        </header>

        {/* Content */}
        <main className="p-8 max-w-7xl mx-auto w-full">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React from 'react';
import { useStore } from '../store';
import { Role, User } from '../types';
import { Users, Building2, UserPlus, History } from 'lucide-react';

const Dashboard: React.FC<{ user: User }> = ({ user }) => {
  const { branches, users, beneficiaries, families, logs } = useStore();

  const isAdmin = user.role === Role.ADMIN;

  // Filter counts based on permissions
  const visibleBeneficiaries = isAdmin 
    ? beneficiaries 
    : beneficiaries.filter(b => b.branchId === user.branchId);

  const stats = [
    { label: 'إجمالي المستفيدين', value: visibleBeneficiaries.length, icon: <Users />, color: 'bg-blue-500' },
    { label: 'إجمالي الأسر', value: families.length, icon: <Users />, color: 'bg-emerald-500' },
    ...(isAdmin ? [
      { label: 'عدد الفروع', value: branches.length, icon: <Building2 />, color: 'bg-purple-500' },
      { label: 'عدد المستخدمين', value: users.length, icon: <UserPlus />, color: 'bg-orange-500' },
    ] : []),
    { label: 'عمليات السجل', value: logs.length, icon: <History />, color: 'bg-gray-500' },
  ];

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold text-gray-800">لوحة التحكم</h1>
        <p className="text-gray-500 mt-2">نظرة عامة على البيانات الحالية</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => (
          <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center gap-5">
            <div className={`p-4 rounded-lg text-white ${stat.color}`}>
              {stat.icon}
            </div>
            <div>
              <p className="text-sm text-gray-500 font-medium">{stat.label}</p>
              <p className="text-2xl font-bold text-gray-800">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-8">
        <h3 className="text-lg font-bold mb-4">نشاط النظام الأخير</h3>
        <div className="space-y-4">
          {logs.slice(0, 5).map((log) => (
            <div key={log.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-lg text-sm border-r-4 border-emerald-500">
              <div>
                <span className="font-bold">{log.userName}</span> قام بـ {log.action} ({log.entityType})
              </div>
              <div className="text-gray-400">
                {new Date(log.timestamp).toLocaleString('ar-EG')}
              </div>
            </div>
          ))}
          {logs.length === 0 && <p className="text-center text-gray-400 py-10">لا توجد سجلات بعد</p>}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { useStore } from '../store';
import { Role, User, Beneficiary, BeneficiaryStatus, BeneficiaryType } from '../types';
import { Plus, Search, Filter, Edit3, Trash2, User as UserIcon, Users as UsersIcon } from 'lucide-react';

const Beneficiaries: React.FC<{ user: User }> = ({ user }) => {
  const store = useStore();
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<BeneficiaryType>(BeneficiaryType.INDIVIDUAL);
  const [editId, setEditId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    nationalId: '',
    phone: '',
    address: '',
    status: BeneficiaryStatus.ACTIVE
  });

  const isAdmin = user.role === Role.ADMIN;

  const filteredBeneficiaries = store.beneficiaries.filter(b => {
    const isOwner = isAdmin || b.branchId === user.branchId;
    const matchesSearch = b.name.includes(searchTerm) || b.nationalId.includes(searchTerm);
    return isOwner && matchesSearch;
  });

  const handleOpenModal = (type: BeneficiaryType, id: string | null = null) => {
    setModalType(type);
    if (id) {
      const b = store.beneficiaries.find(x => x.id === id);
      if (b) {
        setFormData({
          name: b.name,
          nationalId: b.nationalId,
          phone: b.phone,
          address: b.address,
          status: b.status
        });
        setEditId(id);
      }
    } else {
      setFormData({ name: '', nationalId: '', phone: '', address: '', status: BeneficiaryStatus.ACTIVE });
      setEditId(null);
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    let newBeneficiaries = [...store.beneficiaries];
    if (editId) {
      newBeneficiaries = newBeneficiaries.map(b => 
        b.id === editId ? { ...b, ...formData } : b
      );
      store.addLog(user, 'تعديل بيانات', 'مستفيد', editId);
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      const newB: Beneficiary = {
        ...formData,
        id: newId,
        branchId: user.branchId, // Mandatory requirement: auto-assigned to user's branch
        type: modalType,
        createdAt: new Date().toISOString()
      };
      newBeneficiaries.push(newB);
      store.addLog(user, 'إضافة', modalType, newId);
    }
    store.saveBeneficiaries(newBeneficiaries);
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا السجل؟')) {
      const updated = store.beneficiaries.filter(b => b.id !== id);
      store.saveBeneficiaries(updated);
      store.addLog(user, 'حذف', 'مستفيد', id);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">المستفيدين</h1>
          <p className="text-gray-500">إدارة الأفراد والأسر في فرعك</p>
        </div>
        <div className="flex gap-3">
          <button 
            onClick={() => handleOpenModal(BeneficiaryType.INDIVIDUAL)}
            className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition"
          >
            <UserIcon size={18} />
            <span>إضافة فرد</span>
          </button>
          <button 
            onClick={() => handleOpenModal(BeneficiaryType.FAMILY_HEAD)}
            className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition"
          >
            <UsersIcon size={18} />
            <span>إضافة أسرة</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50 flex gap-4">
          <div className="relative flex-1">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="ابحث بالاسم أو الرقم القومي..." 
              className="w-full pr-10 pl-4 py-2 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-emerald-500 text-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button className="flex items-center gap-2 bg-white px-4 py-2 rounded-lg border border-gray-200 text-gray-600 text-sm hover:bg-gray-100">
            <Filter size={18} />
            <span>تصفية</span>
          </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-gray-50 text-gray-500 text-xs font-bold uppercase tracking-wider border-b border-gray-100">
                <th className="px-6 py-4">الاسم</th>
                <th className="px-6 py-4">الرقم القومي</th>
                <th className="px-6 py-4">الهاتف</th>
                <th className="px-6 py-4">النوع</th>
                <th className="px-6 py-4">الفرع</th>
                <th className="px-6 py-4">الحالة</th>
                <th className="px-6 py-4">الإجراءات</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredBeneficiaries.map((b) => (
                <tr key={b.id} className="hover:bg-gray-50 transition">
                  <td className="px-6 py-4 font-semibold text-gray-800">{b.name}</td>
                  <td className="px-6 py-4 text-sm text-gray-600">{b.nationalId}</td>
                  <td className="px-6 py-4 text-sm text-gray-600">{b.phone}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded text-[10px] font-bold ${
                      b.type === BeneficiaryType.INDIVIDUAL ? 'bg-blue-100 text-blue-700' : 'bg-indigo-100 text-indigo-700'
                    }`}>
                      {b.type}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-600">{b.branchId}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                      b.status === BeneficiaryStatus.ACTIVE ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                    }`}>
                      {b.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 flex gap-2">
                    <button 
                      onClick={() => handleOpenModal(b.type, b.id)}
                      className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"
                    >
                      <Edit3 size={16} />
                    </button>
                    <button 
                      onClick={() => handleDelete(b.id)}
                      className="p-1.5 text-red-600 hover:bg-red-50 rounded"
                    >
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredBeneficiaries.length === 0 && (
            <div className="p-10 text-center text-gray-400">لا يوجد مستفيدين مطابقين للبحث</div>
          )}
        </div>
      </div>

      {/* MODAL */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden">
            <div className="p-6 border-b border-gray-100 bg-gray-50">
              <h3 className="text-xl font-bold">{editId ? 'تعديل' : 'إضافة'} {modalType}</h3>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">الاسم الكامل</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">الرقم القومي (14 رقم)</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.nationalId}
                  onChange={(e) => setFormData({ ...formData, nationalId: e.target.value })}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">رقم الهاتف</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.phone}
                  onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">العنوان بالتفصيل</label>
                <textarea 
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none h-20"
                  value={formData.address}
                  onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">الحالة</label>
                <select 
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  value={formData.status}
                  onChange={(e) => setFormData({ ...formData, status: e.target.value as BeneficiaryStatus })}
                >
                  <option value={BeneficiaryStatus.ACTIVE}>{BeneficiaryStatus.ACTIVE}</option>
                  <option value={BeneficiaryStatus.SUSPENDED}>{BeneficiaryStatus.SUSPENDED}</option>
                </select>
              </div>
              <div className="text-xs text-gray-400 mt-2">
                * الفرع سيتم تحديده تلقائياً: {user.branchId}
              </div>
            </div>
            <div className="p-6 bg-gray-50 flex gap-3 justify-end">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="px-6 py-2 border border-gray-300 rounded-lg text-gray-600 hover:bg-gray-100 transition"
              >
                إلغاء
              </button>
              <button 
                onClick={handleSave}
                className="px-6 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition font-bold"
              >
                حفظ
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Beneficiaries;

import React from 'react';
import { useStore } from '../store';
import { History, Search } from 'lucide-react';

const AuditLog: React.FC = () => {
  const { logs } = useStore();

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-gray-800">سجل التعديلات</h1>
        <p className="text-gray-500">سجل تاريخي لكل العمليات التي تمت على النظام</p>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-gray-50 text-gray-500 text-xs font-bold uppercase tracking-wider border-b border-gray-100">
                <th className="px-6 py-4">المستخدم</th>
                <th className="px-6 py-4">العملية</th>
                <th className="px-6 py-4">نوع الكيان</th>
                <th className="px-6 py-4">معرف الكيان</th>
                <th className="px-6 py-4">التاريخ والوقت</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {logs.map((log) => (
                <tr key={log.id} className="hover:bg-gray-50 transition">
                  <td className="px-6 py-4 font-bold text-gray-700">{log.userName}</td>
                  <td className="px-6 py-4">
                    <span className="text-emerald-600 font-semibold">{log.action}</span>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-600">{log.entityType}</td>
                  <td className="px-6 py-4 text-xs font-mono text-gray-400">{log.entityId}</td>
                  <td className="px-6 py-4 text-sm text-gray-500">
                    {new Date(log.timestamp).toLocaleString('ar-EG')}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {logs.length === 0 && (
            <div className="p-10 text-center text-gray-400 flex flex-col items-center gap-2">
              <History size={48} className="opacity-20" />
              <span>لا توجد سجلات بعد</span>
