import React, { useState, useMemo } from 'react';
import { useStore } from '../store';
import { Role, User, Beneficiary, BeneficiaryStatus, BeneficiaryType } from '../types';
import { 
  Plus, Search, Filter, Edit3, Trash2, 
  User as UserIcon, Users as UsersIcon, X, 
  CheckSquare, Square, AlertCircle 
} from 'lucide-react';

const Beneficiaries: React.FC<{ user: User }> = ({ user }) => {
  const store = useStore();
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<BeneficiaryType>(BeneficiaryType.INDIVIDUAL);
  const [editId, setEditId] = useState<string | null>(null);

  // Multi-selection state
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    nationalId: '',
    phone: '',
    address: '',
    status: BeneficiaryStatus.ACTIVE
  });

  // Validation State
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const isAdmin = user.role === Role.ADMIN;

  const filteredBeneficiaries = useMemo(() => {
    return store.beneficiaries.filter(b => {
      const isOwner = isAdmin || b.branchId === user.branchId;
      const matchesSearch = b.name.includes(searchTerm) || b.nationalId.includes(searchTerm);
      return isOwner && matchesSearch;
    });
  }, [store.beneficiaries, searchTerm, user.branchId, isAdmin]);

  const validate = () => {
    const newErrors: { [key: string]: string } = {};

    if (!formData.name.trim()) {
      newErrors.name = 'الاسم مطلوب';
    } else if (formData.name.trim().length < 3) {
      newErrors.name = 'الاسم يجب أن يكون 3 أحرف على الأقل';
    }

    if (!/^\d{14}$/.test(formData.nationalId)) {
      newErrors.nationalId = 'الرقم القومي يجب أن يتكون من 14 رقماً';
    }

    if (!/^01[0125]\d{8}$/.test(formData.phone)) {
      newErrors.phone = 'يجب إدخال رقم هاتف مصري صحيح (مثلاً: 01012345678)';
    }

    if (!formData.address.trim()) {
      newErrors.address = 'العنوان مطلوب';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleOpenModal = (type: BeneficiaryType, id: string | null = null) => {
    setModalType(type);
    setErrors({});
    if (id) {
      const b = store.beneficiaries.find(x => x.id === id);
      if (b) {
        setFormData({
          name: b.name,
          nationalId: b.nationalId,
          phone: b.phone,
          address: b.address,
          status: b.status
        });
        setEditId(id);
      }
    } else {
      setFormData({ name: '', nationalId: '', phone: '', address: '', status: BeneficiaryStatus.ACTIVE });
      setEditId(null);
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    if (!validate()) return;

    let newBeneficiaries = [...store.beneficiaries];
    if (editId) {
      newBeneficiaries = newBeneficiaries.map(b => 
        b.id === editId ? { ...b, ...formData } : b
      );
      store.addLog(user, 'تعديل بيانات', 'مستفيد', editId);
    } else {
      const newId = Math.random().toString(36).substr(2, 9);
      const newB: Beneficiary = {
        ...formData,
        id: newId,
        branchId: user.branchId,
        type: modalType,
        createdAt: new Date().toISOString()
      };
      newBeneficiaries.push(newB);
      store.addLog(user, 'إضافة', modalType, newId);
    }
    store.saveBeneficiaries(newBeneficiaries);
    setIsModalOpen(false);
  };

  const handleDelete = (ids: string[]) => {
    const message = ids.length === 1 
      ? 'هل أنت متأكد من حذف هذا السجل؟' 
      : `هل أنت متأكد من حذف ${ids.length} سجل؟`;

    if (window.confirm(message)) {
      const idSet = new Set(ids);
      const updated = store.beneficiaries.filter(b => !idSet.has(b.id));
      store.saveBeneficiaries(updated);

      ids.forEach(id => store.addLog(user, 'حذف', 'مستفيد', id));

      // Clear selection
      const newSelected = new Set(selectedIds);
      ids.forEach(id => newSelected.delete(id));
      setSelectedIds(newSelected);
    }
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === filteredBeneficiaries.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredBeneficiaries.map(b => b.id)));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">المستفيدين</h1>
          <p className="text-gray-500">إدارة الأفراد والأسر في فرعك</p>
        </div>
        <div className="flex flex-wrap gap-3 w-full lg:w-auto">
          {selectedIds.size > 0 && (
            <button 
              onClick={() => handleDelete(Array.from(selectedIds))}
              className="flex-1 lg:flex-none flex items-center justify-center gap-2 bg-red-100 text-red-700 px-4 py-2 rounded-lg hover:bg-red-200 transition font-bold"
            >
              <Trash2 size={18} />
              <span>حذف المحدد ({selectedIds.size})</span>
            </button>
          )}
          <button 
            onClick={() => handleOpenModal(BeneficiaryType.INDIVIDUAL)}
            className="flex-1 lg:flex-none flex items-center justify-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition shadow-sm font-bold"
          >
            <UserIcon size={18} />
            <span>إضافة فرد</span>
          </button>
          <button 
            onClick={() => handleOpenModal(BeneficiaryType.FAMILY_HEAD)}
            className="flex-1 lg:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition shadow-sm font-bold"
          >
            <UsersIcon size={18} />
            <span>إضافة أسرة</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50 flex flex-col sm:flex-row gap-4">
          <div className="relative flex-1 w-full">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="ابحث بالاسم أو الرقم القومي..." 
              className="w-full pr-10 pl-4 py-2 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-emerald-500 text-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button className="flex items-center justify-center gap-2 bg-white px-4 py-2 rounded-lg border border-gray-200 text-gray-600 text-sm hover:bg-gray-100 transition shadow-sm">
            <Filter size={18} />
            <span>تصفية</span>
          </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-gray-50 text-gray-500 text-xs font-bold uppercase tracking-wider border-b border-gray-100">
                <th className="px-6 py-4 w-10">
                  <button onClick={toggleSelectAll} className="text-emerald-600">
                    {selectedIds.size === filteredBeneficiaries.length && filteredBeneficiaries.length > 0 
                      ? <CheckSquare size={20} /> 
                      : <Square size={20} />
                    }
                  </button>
                </th>
                <th className="px-6 py-4">الاسم</th>
                <th className="px-6 py-4">الرقم القومي</th>
                <th className="px-6 py-4">الهاتف</th>
                <th className="px-6 py-4">النوع</th>
                <th className="px-6 py-4">الفرع</th>
                <th className="px-6 py-4">الحالة</th>
                <th className="px-6 py-4">الإجراءات</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredBeneficiaries.map((b) => (
                <tr key={b.id} className={`hover:bg-emerald-50/30 transition ${selectedIds.has(b.id) ? 'bg-emerald-50' : ''}`}>
                  <td className="px-6 py-4">
                    <button onClick={() => toggleSelect(b.id)} className="text-emerald-600">
                      {selectedIds.has(b.id) ? <CheckSquare size={20} /> : <Square size={20} />}
                    </button>
                  </td>
                  <td className="px-6 py-4 font-semibold text-gray-800 whitespace-nowrap">{b.name}</td>
                  <td className="px-6 py-4 text-sm text-gray-600 whitespace-nowrap">{b.nationalId}</td>
                  <td className="px-6 py-4 text-sm text-gray-600 whitespace-nowrap">{b.phone}</td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-2 py-1 rounded text-[10px] font-bold ${
                      b.type === BeneficiaryType.INDIVIDUAL ? 'bg-blue-100 text-blue-700' : 'bg-indigo-100 text-indigo-700'
