                onClick={handleSave}
                className="flex-1 px-6 py-2.5 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition font-bold shadow-lg shadow-emerald-600/20 active:scale-[0.98]"
              >
                {editId ? 'تحديث البيانات' : 'حفظ البيانات'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

