import React, { useState } from 'react';
import { useStore } from '../store';
import { User, Branch } from '../types';
import { Plus, Edit3, Trash2, MapPin, X } from 'lucide-react';

const Branches: React.FC<{ user: User }> = ({ user }) => {
  const { branches, setBranches, addLog } = useStore();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [formData, setFormData] = useState({ name: '', location: '' });

  const handleOpenModal = (id: string | null = null) => {
    if (id) {
      const b = branches.find(x => x.id === id);
      if (b) { setFormData({ name: b.name, location: b.location }); setEditId(id); }
    } else {
      setFormData({ name: '', location: '' }); setEditId(null);
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    let updated;
    if (editId) {
      updated = branches.map(b => b.id === editId ? { ...b, ...formData } : b);
      addLog(user, 'تعديل', 'فرع', editId);
    } else {
      const newId = 'b' + (branches.length + 1);
      updated = [...branches, { ...formData, id: newId, createdAt: new Date().toISOString() }];
      addLog(user, 'إضافة', 'فرع', newId);
    }
    setBranches(updated);
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الفرع؟')) {
      const updated = branches.filter(b => b.id !== id);
      setBranches(updated);
      addLog(user, 'حذف', 'فرع', id);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div><h1 className="text-3xl font-bold text-gray-800">الفروع</h1><p className="text-gray-500">إدارة فروع الجمعية</p></div>
        <button onClick={() => handleOpenModal()} className="bg-emerald-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 font-bold"><Plus size={18} /> إضافة فرع</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {branches.map(branch => (
          <div key={branch.id} className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 relative group">
            <div className="absolute top-4 left-4 opacity-0 group-hover:opacity-100 transition flex gap-2">
               <button onClick={() => handleOpenModal(branch.id)} className="p-1.5 text-blue-600 bg-white border rounded"><Edit3 size={16} /></button>
               <button onClick={() => handleDelete(branch.id)} className="p-1.5 text-red-600 bg-white border rounded"><Trash2 size={16} /></button>
            </div>
            <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-lg flex items-center justify-center mb-4"><MapPin size={24} /></div>
            <h3 className="font-bold text-lg">{branch.name}</h3>
            <p className="text-sm text-gray-500">{branch.location}</p>
          </div>
        ))}
      </div>
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md p-6">
            <h3 className="text-xl font-bold mb-4">{editId ? 'تعديل' : 'إضافة'} فرع</h3>
            <div className="space-y-4">
              <input type="text" placeholder="اسم الفرع" className="w-full px-4 py-2 border rounded-xl" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
              <input type="text" placeholder="الموقع" className="w-full px-4 py-2 border rounded-xl" value={formData.location} onChange={e => setFormData({...formData, location: e.target.value})} />
            </div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => setIsModalOpen(false)} className="flex-1 py-2 border rounded-xl">إلغاء</button>
              <button onClick={handleSave} className="flex-1 py-2 bg-emerald-600 text-white rounded-xl">حفظ</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

