import React, { useState, useMemo } from 'react';
import { useStore } from '../store';
import { User, Beneficiary, BeneficiaryStatus, BeneficiaryType, Role } from '../types';
import { 
  Plus, Search, Edit3, Trash2, 
  User as UserIcon, Users as UsersIcon, X, 
  CheckSquare, Square, LayoutList, Network, MapPin
} from 'lucide-react';

const Beneficiaries: React.FC<{ user: User }> = ({ user }) => {
  const { beneficiaries, setBeneficiaries, regions, addLog } = useStore();
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<BeneficiaryType>(BeneficiaryType.INDIVIDUAL);
  const [editId, setEditId] = useState<string | null>(null);
  const [isTreeView, setIsTreeView] = useState(false);

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [formData, setFormData] = useState({
    name: '',
    nationalId: '',
    phone: '',
    address: '',
    regionId: '',
    status: BeneficiaryStatus.ACTIVE,
    familyId: ''
  });
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const isAdmin = user.role === Role.ADMIN;

  const filteredBeneficiaries = useMemo(() => {
    return beneficiaries.filter(b => {
      const isOwner = isAdmin || b.branchId === user.branchId;
      const matchesSearch = b.name.includes(searchTerm) || b.nationalId.includes(searchTerm);
      return isOwner && matchesSearch;
    });
  }, [beneficiaries, searchTerm, user.branchId, isAdmin]);

  const treeData = useMemo(() => {
    const heads = filteredBeneficiaries.filter(b => b.type === BeneficiaryType.FAMILY_HEAD);
    const others = filteredBeneficiaries.filter(b => b.type === BeneficiaryType.INDIVIDUAL || (b.type === BeneficiaryType.FAMILY_MEMBER && !b.familyId));

    return [
      ...heads.map(head => ({
        ...head,
        members: filteredBeneficiaries.filter(m => m.familyId === head.id)
      })),
      ...others.map(o => ({ ...o, members: [] }))
    ];
  }, [filteredBeneficiaries]);

  const validate = () => {
    const newErrors: { [key: string]: string } = {};
    if (!formData.name.trim()) newErrors.name = 'الاسم مطلوب';
    if (!/^\d{14}$/.test(formData.nationalId)) newErrors.nationalId = 'الرقم القومي يجب أن يكون 14 رقماً';
    if (!/^01[0125]\d{8}$/.test(formData.phone)) newErrors.phone = 'رقم هاتف غير صحيح';
    if (!formData.address.trim()) newErrors.address = 'العنوان مطلوب';
    if (!formData.regionId) newErrors.regionId = 'يجب اختيار المنطقة';
    if (modalType === BeneficiaryType.FAMILY_MEMBER && !formData.familyId) newErrors.familyId = 'يجب اختيار رب الأسرة';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleOpenModal = (type: BeneficiaryType, id: string | null = null) => {
    setModalType(type);
    setErrors({});
    if (id) {
      const b = beneficiaries.find(x => x.id === id);
      if (b) {
        setFormData({ 
          name: b.name, 
          nationalId: b.nationalId, 
          phone: b.phone, 
          address: b.address, 
          regionId: b.regionId || '',
          status: b.status, 
          familyId: b.familyId || '' 
        });
        setEditId(id);
      }
    } else {
      setFormData({ name: '', nationalId: '', phone: '', address: '', regionId: '', status: BeneficiaryStatus.ACTIVE, familyId: '' });
      setEditId(null);
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    if (!validate()) return;

    let updated: Beneficiary[] = [];
    if (editId) {
      updated = beneficiaries.map(b => b.id === editId ? { ...b, ...formData } : b);
      addLog(user, 'تعديل', 'مستفيد', editId);
    } else {
      const newId = Math.random().toString(36).substring(2, 11);
      const newB: Beneficiary = { 
        ...formData, 
        id: newId, 
        branchId: user.branchId, 
        type: modalType, 
        createdAt: new Date().toISOString() 
      };
      updated = [...beneficiaries, newB];
      addLog(user, 'إضافة', modalType, newId);
    }
    setBeneficiaries(updated);
    setIsModalOpen(false);
  };

  const handleDelete = (ids: string[]) => {
    if (window.confirm(`هل أنت متأكد من حذف السجلات المحددة؟`)) {
      const updated = beneficiaries.filter(b => !ids.includes(b.id));
      setBeneficiaries(updated);
      ids.forEach(id => addLog(user, 'حذف', 'مستفيد', id));
      setSelectedIds(new Set());
    }
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id); else next.add(id);
    setSelectedIds(next);
  };

  const familyHeads = useMemo(() => 
    beneficiaries.filter(b => b.type === BeneficiaryType.FAMILY_HEAD && b.branchId === user.branchId),
  [beneficiaries, user.branchId]);

  const branchRegions = useMemo(() => 
    regions.filter(r => r.branchId === user.branchId),
  [regions, user.branchId]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">إدارة المستفيدين</h1>
          <p className="text-gray-500">سجل رقمي متكامل لإدارة الحالات</p>
        </div>
        <div className="flex flex-wrap gap-2 w-full lg:w-auto">
          {selectedIds.size > 0 && (
            <button onClick={() => handleDelete(Array.from(selectedIds))} className="bg-red-50 text-red-600 px-4 py-2 rounded-lg font-bold border border-red-100 flex items-center gap-2 hover:bg-red-100">
              <Trash2 size={18} /> حذف ({selectedIds.size})
            </button>
          )}
          <button onClick={() => setIsTreeView(!isTreeView)} className="bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-gray-50 font-bold">
            {isTreeView ? <LayoutList size={18} /> : <Network size={18} />}
            <span>{isTreeView ? 'عرض القائمة' : 'عرض شجري'}</span>
          </button>
          <button onClick={() => handleOpenModal(BeneficiaryType.INDIVIDUAL)} className="bg-emerald-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-emerald-700 shadow-sm font-bold">
            <UserIcon size={18} /> إضافة فرد
          </button>
          <button onClick={() => handleOpenModal(BeneficiaryType.FAMILY_HEAD)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm font-bold">
            <UsersIcon size={18} /> إضافة رب أسرة
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50">
          <div className="relative max-w-md">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input type="text" placeholder="ابحث بالاسم أو الرقم القومي..." className="w-full pr-10 pl-4 py-2 rounded-lg border border-gray-200 focus:ring-2 focus:ring-emerald-500 text-sm" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>

        <div className="overflow-x-auto">
          {isTreeView ? (
            <div className="p-4 space-y-4">
              {treeData.map(node => (
                <div key={node.id} className="border border-gray-100 rounded-xl overflow-hidden shadow-sm bg-white">
                  <div className="bg-gray-50 p-4 flex items-center justify-between border-b border-gray-100">
                    <div className="flex items-center gap-4">
                      <button onClick={() => toggleSelect(node.id)} className="text-emerald-600">
                        {selectedIds.has(node.id) ? <CheckSquare size={20} /> : <Square size={20} />}
                      </button>
                      <div>
                        <p className="font-bold text-gray-800">{node.name} <span className="text-xs font-normal text-gray-500 bg-indigo-50 px-2 rounded">{node.type}</span></p>
                        <p className="text-xs text-gray-500 flex items-center gap-2 mt-1">
                          <MapPin size={12} className="text-emerald-500" />
                          {regions.find(r => r.id === node.regionId)?.name || 'غير محدد'} | {node.nationalId}
                        </p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                       <button onClick={() => handleOpenModal(node.type, node.id)} className="p-1.5 text-blue-600 bg-white rounded border border-gray-200 hover:bg-blue-50 transition shadow-sm"><Edit3 size={16} /></button>
                       <button onClick={() => handleDelete([node.id])} className="p-1.5 text-red-600 bg-white rounded border border-gray-200 hover:bg-red-50 transition shadow-sm"><Trash2 size={16} /></button>
                    </div>
                  </div>
                  {node.members.length > 0 && (
                    <div className="divide-y divide-gray-50 bg-white">
                      {node.members.map(member => (
                        <div key={member.id} className="pr-12 p-3 flex items-center justify-between hover:bg-gray-50 transition">
                          <div className="flex items-center gap-3">
                             <div className="w-px h-6 bg-gray-200 -mr-4"></div>
                             <div className="w-2 h-2 rounded-full bg-blue-400"></div>
                             <div>
                               <p className="text-sm font-semibold">{member.name}</p>
                               <p className="text-[10px] text-gray-400">{regions.find(r => r.id === member.regionId)?.name || 'غير محدد'} | {member.nationalId}</p>
                             </div>
                          </div>
                          <div className="flex gap-2">
                            <button onClick={() => handleOpenModal(member.type, member.id)} className="text-gray-400 hover:text-blue-600 transition"><Edit3 size={14} /></button>
                            <button onClick={() => handleDelete([member.id])} className="text-gray-400 hover:text-red-600 transition"><Trash2 size={14} /></button>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                  {node.type === BeneficiaryType.FAMILY_HEAD && (
                    <div className="p-2 bg-gray-50/50 flex justify-center border-t border-gray-50">
                        <button onClick={() => { setFormData({ ...formData, familyId: node.id }); handleOpenModal(BeneficiaryType.FAMILY_MEMBER); }} className="text-xs font-bold text-indigo-600 flex items-center gap-1 hover:underline">
                            <Plus size={12} /> إضافة فرد لهذه الأسرة
                        </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          ) : (
            <table className="w-full text-right">
              <thead>
                <tr className="bg-gray-50 text-gray-500 text-xs font-bold uppercase tracking-wider border-b border-gray-100">
                  <th className="px-6 py-4 w-10"></th>
                  <th className="px-6 py-4">الاسم</th>
                  <th className="px-6 py-4">المنطقة</th>
                  <th className="px-6 py-4">الهاتف</th>
                  <th className="px-6 py-4">النوع</th>
                  <th className="px-6 py-4">الحالة</th>
                  <th className="px-6 py-4">الإجراءات</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {filteredBeneficiaries.map(b => (
                  <tr key={b.id} className={`hover:bg-gray-50 transition ${selectedIds.has(b.id) ? 'bg-emerald-50' : ''}`}>
                    <td className="px-6 py-4">
                      <button onClick={() => toggleSelect(b.id)} className="text-emerald-600">
                        {selectedIds.has(b.id) ? <CheckSquare size={20} /> : <Square size={20} />}
                      </button>
                    </td>
                    <td className="px-6 py-4 font-semibold text-gray-800">{b.name}</td>
                    <td className="px-6 py-4 text-sm text-emerald-600 font-bold">
                      {regions.find(r => r.id === b.regionId)?.name || '---'}
                    </td>
                    <td className="px-6 py-4 text-sm">{b.phone}</td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded text-[10px] font-bold ${b.type === BeneficiaryType.INDIVIDUAL ? 'bg-gray-100 text-gray-600' : b.type === BeneficiaryType.FAMILY_HEAD ? 'bg-indigo-100 text-indigo-700' : 'bg-blue-100 text-blue-700'}`}>
                        {b.type}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${b.status === BeneficiaryStatus.ACTIVE ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                        {b.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 flex gap-2">
                      <button onClick={() => handleOpenModal(b.type, b.id)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded transition"><Edit3 size={16} /></button>
                      <button onClick={() => handleDelete([b.id])} className="p-1.5 text-red-600 hover:bg-red-50 rounded transition"><Trash2 size={16} /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md flex flex-col max-h-[90vh] overflow-hidden">
            <div className="p-6 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
              <h3 className="text-xl font-bold">{editId ? 'تعديل' : 'إضافة'} {modalType}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 transition"><X size={20} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-6 space-y-4">
              {modalType === BeneficiaryType.FAMILY_MEMBER && (
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">اختيار رب الأسرة</label>
                  <select className={`w-full px-4 py-2.5 border rounded-xl bg-white ${errors.familyId ? 'border-red-500' : 'border-gray-300'}`} value={formData.familyId} onChange={(e) => setFormData({ ...formData, familyId: e.target.value })}>
                    <option value="">-- اختر من القائمة --</option>
                    {familyHeads.map(h => <option key={h.id} value={h.id}>{h.name}</option>)}
                  </select>
                  {errors.familyId && <p className="text-red-500 text-xs mt-1">{errors.familyId}</p>}
                </div>
              )}

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">المنطقة</label>
                <select 
                  className={`w-full px-4 py-2.5 border rounded-xl bg-white ${errors.regionId ? 'border-red-500' : 'border-gray-300'}`} 
                  value={formData.regionId} 
                  onChange={(e) => setFormData({ ...formData, regionId: e.target.value })}
                >
                  <option value="">-- اختر المنطقة السكنية --</option>
                  {branchRegions.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                </select>
                {errors.regionId && <p className="text-red-500 text-xs mt-1">{errors.regionId}</p>}
                {branchRegions.length === 0 && <p className="text-orange-500 text-[10px] mt-1">يجب إضافة مناطق أولاً من شاشة المناطق.</p>}
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">الاسم الكامل</label>
                <input type="text" className={`w-full px-4 py-2.5 border rounded-xl ${errors.name ? 'border-red-500' : 'border-gray-300'}`} value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} />
                {errors.name && <p className="text-red-500 text-xs mt-1">{errors.name}</p>}
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">الرقم القومي</label>
                <input type="text" maxLength={14} className={`w-full px-4 py-2.5 border rounded-xl ${errors.nationalId ? 'border-red-500' : 'border-gray-300'}`} value={formData.nationalId} onChange={(e) => setFormData({ ...formData, nationalId: e.target.value.replace(/\D/g, '') })} />
                {errors.nationalId && <p className="text-red-500 text-xs mt-1">{errors.nationalId}</p>}
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">رقم الهاتف</label>
                <input type="text" maxLength={11} className={`w-full px-4 py-2.5 border rounded-xl ${errors.phone ? 'border-red-500' : 'border-gray-300'}`} value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value.replace(/\D/g, '') })} />
                {errors.phone && <p className="text-red-500 text-xs mt-1">{errors.phone}</p>}
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">العنوان بالتفصيل</label>
                <textarea className={`w-full px-4 py-2.5 border rounded-xl h-20 resize-none ${errors.address ? 'border-red-500' : 'border-gray-300'}`} value={formData.address} onChange={(e) => setFormData({ ...formData, address: e.target.value })} />
                {errors.address && <p className="text-red-500 text-xs mt-1">{errors.address}</p>}
              </div>
            </div>
            <div className="p-6 bg-gray-50 border-t flex gap-3">
              <button onClick={() => setIsModalOpen(false)} className="flex-1 py-2.5 border border-gray-300 rounded-xl font-bold hover:bg-white transition">إلغاء</button>
              <button onClick={handleSave} className="flex-1 py-2.5 bg-emerald-600 text-white rounded-xl font-bold shadow-lg shadow-emerald-600/20 hover:bg-emerald-700 transition">حفظ</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Beneficiaries;

export enum Role {
  ADMIN = 'Admin',
  MANAGER = 'Manager',
  STAFF = 'Staff'
}

export enum BeneficiaryStatus {
  ACTIVE = 'نشط',
  SUSPENDED = 'موقوف'
}

export enum BeneficiaryType {
  INDIVIDUAL = 'فرد',
  FAMILY_HEAD = 'رب أسرة',
  FAMILY_MEMBER = 'فرد أسرة'
}

export interface Branch {
  id: string;
  name: string;
  location: string;
  createdAt: string;
}

export interface Region {
  id: string;
  name: string;
  branchId: string;
}

export interface User {
  id: string;
  name: string;
  username: string;
  password?: string;
  role: Role;
  branchId: string; // Linked to a branch
}

export interface Beneficiary {
  id: string;
  name: string;
  nationalId: string;
  phone: string;
  address: string;
  birthDate: string; // New field added
  regionId?: string;
  branchId: string;
  status: BeneficiaryStatus;
  type: BeneficiaryType;
  familyId?: string; // If part of a family
  createdAt: string;
}

export interface Family {
  id: string;
  name: string;
  headId: string;
  branchId: string;
  membersCount: number;
}

export interface AuditLog {
  id: string;
  userId: string;
  userName: string;
  action: string;
  entityType: string;
  entityId: string;
  timestamp: string;
}

