                {errors.name && <p className="text-red-500 text-xs mt-1">{errors.name}</p>}
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">الرقم القومي</label>
                <input type="text" maxLength={14} className={`w-full px-4 py-2.5 border rounded-xl ${errors.nationalId ? 'border-red-500' : 'border-gray-300'}`} value={formData.nationalId} onChange={(e) => setFormData({ ...formData, nationalId: e.target.value.replace(/\D/g, '') })} />
                {errors.nationalId && <p className="text-red-500 text-xs mt-1">{errors.nationalId}</p>}
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">رقم الهاتف</label>
                <input type="text" maxLength={11} className={`w-full px-4 py-2.5 border rounded-xl ${errors.phone ? 'border-red-500' : 'border-gray-300'}`} value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value.replace(/\D/g, '') })} />
                {errors.phone && <p className="text-red-500 text-xs mt-1">{errors.phone}</p>}
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">العنوان بالتفصيل</label>
                <textarea className={`w-full px-4 py-2.5 border rounded-xl h-20 resize-none ${errors.address ? 'border-red-500' : 'border-gray-300'}`} value={formData.address} onChange={(e) => setFormData({ ...formData, address: e.target.value })} />
                {errors.address && <p className="text-red-500 text-xs mt-1">{errors.address}</p>}
              </div>
            </div>
            <div className="p-6 bg-gray-50 border-t flex gap-3">
              <button onClick={() => setIsModalOpen(false)} className="flex-1 py-2.5 border border-gray-300 rounded-xl font-bold hover:bg-white transition">إلغاء</button>
              <button onClick={handleSave} className="flex-1 py-2.5 bg-emerald-600 text-white rounded-xl font-bold shadow-lg shadow-emerald-600/20 hover:bg-emerald-700 transition">حفظ</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

