                    {errors.birthDate && <p className="text-red-500 text-[10px] mt-1">{errors.birthDate}</p>}
                  </div>
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">الاسم الكامل</label>
                <input type="text" className="w-full px-4 py-2.5 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500" value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} />
                {errors.name && <p className="text-red-500 text-xs mt-1">{errors.name}</p>}
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">الرقم القومي</label>
                <input type="text" maxLength={14} className="w-full px-4 py-2.5 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500" value={formData.nationalId} onChange={(e) => setFormData({ ...formData, nationalId: e.target.value.replace(/\D/g, '') })} />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">رقم الهاتف</label>
                <input type="text" maxLength={11} className="w-full px-4 py-2.5 border rounded-xl outline-none focus:ring-2 focus:ring-emerald-500" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value.replace(/\D/g, '') })} />
              </div>
            </div>
            <div className="p-6 bg-gray-50 border-t flex gap-3">
              <button onClick={() => setIsModalOpen(false)} className="flex-1 py-2.5 border border-gray-300 rounded-xl font-bold hover:bg-white transition">إلغاء</button>
              <button onClick={handleSave} className="flex-1 py-2.5 bg-emerald-600 text-white rounded-xl font-bold shadow-lg shadow-emerald-600/20 hover:bg-emerald-700 transition">حفظ</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

