];

const INITIAL_USERS: User[] = [
  { id: 'u1', name: 'أحمد المسؤول', username: 'admin', password: '123', role: Role.ADMIN, branchId: 'b1' },
  { id: 'u2', name: 'محمد مدير الجيزة', username: 'manager', password: '123', role: Role.MANAGER, branchId: 'b2' },
];

const INITIAL_BENEFICIARIES: Beneficiary[] = [
  { 
    id: 'ben1', 
    name: 'محمود عبد الله', 
    nationalId: '12345678901234', 
    phone: '01011223344', 
    address: 'شارع 10، المعادي', 
    birthDate: '1985-05-15',
    branchId: 'b1', 
    regionId: '',
    status: BeneficiaryStatus.ACTIVE, 
    type: BeneficiaryType.INDIVIDUAL, 
    createdAt: new Date().toISOString() 
  },
];

interface StoreContextType {
  branches: Branch[];
  regions: Region[];
  users: User[];
  beneficiaries: Beneficiary[];
  families: Family[];
  logs: AuditLog[];
  setBranches: (data: Branch[]) => void;
  setRegions: (data: Region[]) => void;
  setUsers: (data: User[]) => void;
  saveUsers: (data: User[]) => void;
  setBeneficiaries: (data: Beneficiary[]) => void;
  setFamilies: (data: Family[]) => void;
  addLog: (user: User, action: string, entityType: string, entityId: string) => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [branches, setBranchesState] = useState<Branch[]>(() => {
    const item = localStorage.getItem('branches');
    return item ? JSON.parse(item) : INITIAL_BRANCHES;
  });
  const [regions, setRegionsState] = useState<Region[]>(() => {
    const item = localStorage.getItem('regions');
    return item ? JSON.parse(item) : [];
  });
  const [users, setUsersState] = useState<User[]>(() => {
    const item = localStorage.getItem('users');
    return item ? JSON.parse(item) : INITIAL_USERS;
  });
  const [beneficiaries, setBeneficiariesState] = useState<Beneficiary[]>(() => {
    const item = localStorage.getItem('beneficiaries');
    return item ? JSON.parse(item) : INITIAL_BENEFICIARIES;
  });
  const [families, setFamiliesState] = useState<Family[]>(() => {
    const item = localStorage.getItem('families');
    return item ? JSON.parse(item) : [];
  });
  const [logs, setLogsState] = useState<AuditLog[]>(() => {
    const item = localStorage.getItem('audit_logs');
    return item ? JSON.parse(item) : [];
  });

  const setBranches = (data: Branch[]) => {
    setBranchesState(data);
    localStorage.setItem('branches', JSON.stringify(data));
  };

  const setRegions = (data: Region[]) => {
    setRegionsState(data);
    localStorage.setItem('regions', JSON.stringify(data));
  };

  const setUsers = (data: User[]) => {
    setUsersState(data);
    localStorage.setItem('users', JSON.stringify(data));
  };

  const setBeneficiaries = (data: Beneficiary[]) => {
    setBeneficiariesState(data);
    localStorage.setItem('beneficiaries', JSON.stringify(data));
  };

  const setFamilies = (data: Family[]) => {
    setFamiliesState(data);
    localStorage.setItem('families', JSON.stringify(data));
  };

  const addLog = (user: User, action: string, entityType: string, entityId: string) => {
    const newLog: AuditLog = {
      id: Math.random().toString(36).substring(2, 11),
      userId: user.id,
      userName: user.name,
      action: action,
      entityType: entityType,
      entityId: entityId,
      timestamp: new Date().toISOString()
    };
    setLogsState((prev) => {
      const updated = [newLog, ...prev];
      localStorage.setItem('audit_logs', JSON.stringify(updated));
      return updated;
    });
  };

  return (
    <StoreContext.Provider value={{
      branches, regions, users, beneficiaries, families, logs,
      setBranches, setRegions, setUsers, saveUsers: setUsers, setBeneficiaries, setFamilies, addLog
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error('useStore must be used within a StoreProvider');
  return context;
};

import React, { useState, useMemo } from 'react';
import { useStore } from '../store';
import { User, Beneficiary, BeneficiaryStatus, BeneficiaryType, Role } from '../types';
import { 
  Plus, Search, Edit3, Trash2, 
  User as UserIcon, Users as UsersIcon, X, 
  CheckSquare, Square, LayoutList, Network, MapPin,
  Calendar
} from 'lucide-react';

const Beneficiaries: React.FC<{ user: User }> = ({ user }) => {
  const { beneficiaries, setBeneficiaries, regions, addLog } = useStore();
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<BeneficiaryType>(BeneficiaryType.INDIVIDUAL);
  const [editId, setEditId] = useState<string | null>(null);
  const [isTreeView, setIsTreeView] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  const initialForm = {
    name: '',
    nationalId: '',
    phone: '',
    address: '',
    birthDate: '',
    regionId: '',
    status: BeneficiaryStatus.ACTIVE,
    familyId: ''
  };

  const [formData, setFormData] = useState(initialForm);
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const isAdmin = user.role === Role.ADMIN;

  const filteredBeneficiaries = useMemo(() => {
    return beneficiaries.filter(b => {
      const isOwner = isAdmin || b.branchId === user.branchId;
      const searchLower = searchTerm.toLowerCase();
      const matchesSearch = b.name.toLowerCase().includes(searchLower) || b.nationalId.includes(searchTerm);
      return isOwner && matchesSearch;
    });
  }, [beneficiaries, searchTerm, user.branchId, isAdmin]);

  const treeData = useMemo(() => {
    const heads = filteredBeneficiaries.filter(b => b.type === BeneficiaryType.FAMILY_HEAD);
    const others = filteredBeneficiaries.filter(b => b.type === BeneficiaryType.INDIVIDUAL || (b.type === BeneficiaryType.FAMILY_MEMBER && !b.familyId));

    return [
      ...heads.map(head => ({
        ...head,
        members: filteredBeneficiaries.filter(m => m.familyId === head.id)
      })),
      ...others.map(o => ({ ...o, members: [] }))
    ];
  }, [filteredBeneficiaries]);

  const validate = () => {
    const e: { [key: string]: string } = {};
    if (!formData.name.trim()) e.name = 'الاسم مطلوب';
    if (!/^\d{14}$/.test(formData.nationalId)) e.nationalId = 'الرقم القومي يجب أن يتكون من 14 رقماً';
    if (!formData.birthDate) e.birthDate = 'تاريخ الميلاد مطلوب';
    if (!formData.regionId) e.regionId = 'يجب اختيار المنطقة';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleOpenModal = (type: BeneficiaryType, id: string | null = null) => {
    setModalType(type);
    setErrors({});
    if (id) {
      const b = beneficiaries.find(x => x.id === id);
      if (b) {
        setFormData({ 
          name: b.name, 
          nationalId: b.nationalId, 
          phone: b.phone, 
          address: b.address, 
          birthDate: b.birthDate || '',
          regionId: b.regionId || '',
          status: b.status, 
          familyId: b.familyId || '' 
        });
        setEditId(id);
      }
    } else {
      setFormData(initialForm);
      setEditId(null);
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    if (!validate()) return;

    let updated: Beneficiary[] = [];
    if (editId) {
      updated = beneficiaries.map(b => b.id === editId ? { ...b, ...formData } : b);
      addLog(user, 'تعديل', 'مستفيد', editId);
    } else {
      const newId = Math.random().toString(36).substring(2, 11);
      const newB: Beneficiary = { 
        ...formData, 
        id: newId, 
        branchId: user.branchId, 
        type: modalType, 
        createdAt: new Date().toISOString() 
      };
      updated = [...beneficiaries, newB];
      addLog(user, 'إضافة', modalType, newId);
    }
    setBeneficiaries(updated);
    setIsModalOpen(false);
  };

  const calculateAge = (dob: string) => {
    if (!dob) return '-';
    const birth = new Date(dob);
    const today = new Date();
    let age = today.getFullYear() - birth.getFullYear();
    const monthDiff = today.getMonth() - birth.getMonth();
    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birth.getDate())) {
        age--;
    }
    return age;
  };

  const branchRegions = regions.filter(r => isAdmin || r.branchId === user.branchId);
  const familyHeads = beneficiaries.filter(b => b.type === BeneficiaryType.FAMILY_HEAD && (isAdmin || b.branchId === user.branchId));

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">إدارة المستفيدين</h1>
          <p className="text-gray-500">الأرشفة الرقمية للجمعية</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <button onClick={() => setIsTreeView(!isTreeView)} className="bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-gray-50 font-bold transition shadow-sm">
            {isTreeView ? <LayoutList size={18} /> : <Network size={18} />}
            <span>{isTreeView ? 'عرض القائمة' : 'عرض شجري'}</span>
          </button>
          <button onClick={() => handleOpenModal(BeneficiaryType.INDIVIDUAL)} className="bg-emerald-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-emerald-700 shadow-sm font-bold transition">
            <UserIcon size={18} /> إضافة فرد
          </button>
          <button onClick={() => handleOpenModal(BeneficiaryType.FAMILY_HEAD)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm font-bold transition">
            <UsersIcon size={18} /> إضافة رب أسرة
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50">
          <div className="relative max-w-md">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="ابحث بالاسم أو الرقم القومي..." 
              className="w-full pr-10 pl-4 py-2 rounded-lg border border-gray-200 focus:ring-2 focus:ring-emerald-500 text-sm outline-none" 
              value={searchTerm} 
              onChange={(e) => setSearchTerm(e.target.value)} 
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          {isTreeView ? (
            <div className="p-4 space-y-4">
              {treeData.map(node => (
                <div key={node.id} className="border border-gray-100 rounded-xl overflow-hidden shadow-sm bg-white">
                  <div className="bg-gray-50 p-4 flex items-center justify-between border-b border-gray-100">
                    <div className="flex items-center gap-4">
                      <div>
                        <p className="font-bold text-gray-800">{node.name} <span className="text-xs font-normal text-gray-500 bg-indigo-50 px-2 rounded mr-2">{node.type}</span></p>
                        <p className="text-xs text-gray-500 flex items-center gap-2 mt-1">
                          <MapPin size={12} className="text-emerald-500" />
                          {regions.find(r => r.id === node.regionId)?.name || 'غير محدد'} | 
                          <Calendar size={12} className="text-indigo-500 mr-1 ml-1" />
                          العمر: {calculateAge(node.birthDate)} سنة
                        </p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                       <button onClick={() => handleOpenModal(node.type, node.id)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded transition"><Edit3 size={16} /></button>
                       <button onClick={() => { if(confirm('هل أنت متأكد من الحذف؟')) setBeneficiaries(beneficiaries.filter(x => x.id !== node.id)) }} className="p-1.5 text-red-600 hover:bg-red-50 rounded transition"><Trash2 size={16} /></button>
                    </div>
                  </div>
                  {node.members.length > 0 && (
                    <div className="p-4 bg-white space-y-2">
                      {node.members.map(m => (
                        <div key={m.id} className="flex items-center justify-between text-sm bg-gray-50 p-2 rounded-lg">
                          <span className="font-medium">{m.name}</span>
                          <span className="text-gray-400 text-xs">العمر: {calculateAge(m.birthDate)}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          ) : (
            <table className="w-full text-right">
              <thead className="bg-gray-50 border-b border-gray-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">المستفيد</th>
                  <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">المنطقة</th>
                  <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">العمر</th>
                  <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">الهاتف</th>
                  <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">الإجراءات</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {filteredBeneficiaries.map(b => (
                  <tr key={b.id} className="hover:bg-gray-50 transition">
                    <td className="px-6 py-4 font-semibold text-gray-800">{b.name}</td>
