                      <button onClick={() => { if(confirm('حذف؟')) setBeneficiaries(beneficiaries.filter(x => x.id !== b.id)) }} className="p-1.5 text-red-600 hover:bg-red-50 rounded transition"><Trash2 size={16} /></button>
                    </td>
                  </tr>
