import React, { useState, useMemo } from 'react';
import { useStore, User, Beneficiary, BeneficiaryStatus, BeneficiaryType, Role } from '../store.tsx';
import { 
  Plus, Search, Edit3, Trash2, 
  User as UserIcon, Users as UsersIcon, X, 
  LayoutList, Network, MapPin,
  Calendar
} from 'lucide-react';

const Beneficiaries: React.FC<{ user: User }> = ({ user }) => {
  const { beneficiaries, setBeneficiaries, regions, addLog } = useStore();
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<BeneficiaryType>(BeneficiaryType.INDIVIDUAL);
  const [editId, setEditId] = useState<string | null>(null);
  const [isTreeView, setIsTreeView] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  const initialForm = {
    name: '',
    nationalId: '',
    phone: '',
    address: '',
    birthDate: '',
    regionId: '',
    status: BeneficiaryStatus.ACTIVE,
    familyId: ''
  };

  const [formData, setFormData] = useState(initialForm);
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const isAdmin = user.role === Role.ADMIN;

  const filteredBeneficiaries = useMemo(() => {
    return beneficiaries.filter(b => {
      const isOwner = isAdmin || b.branchId === user.branchId;
      const searchLower = searchTerm.toLowerCase();
      const matchesSearch = b.name.toLowerCase().includes(searchLower) || b.nationalId.includes(searchTerm);
      return isOwner && matchesSearch;
    });
  }, [beneficiaries, searchTerm, user.branchId, isAdmin]);

  const treeData = useMemo(() => {
    const heads = filteredBeneficiaries.filter(b => b.type === BeneficiaryType.FAMILY_HEAD);
    const others = filteredBeneficiaries.filter(b => b.type === BeneficiaryType.INDIVIDUAL || (b.type === BeneficiaryType.FAMILY_MEMBER && !b.familyId));

    return [
      ...heads.map(head => ({
        ...head,
        members: filteredBeneficiaries.filter(m => m.familyId === head.id)
      })),
      ...others.map(o => ({ ...o, members: [] }))
    ];
  }, [filteredBeneficiaries]);

  const validate = () => {
    const e: { [key: string]: string } = {};
    if (!formData.name.trim()) e.name = 'الاسم مطلوب';
    if (!/^\d{14}$/.test(formData.nationalId)) e.nationalId = 'الرقم القومي (14 رقم)';
    if (!formData.birthDate) e.birthDate = 'تاريخ الميلاد مطلوب';
    if (!formData.regionId) e.regionId = 'اختر المنطقة';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleOpenModal = (type: BeneficiaryType, id: string | null = null) => {
    setModalType(type);
    setErrors({});
    if (id) {
      const b = beneficiaries.find(x => x.id === id);
      if (b) {
        setFormData({ 
          name: b.name, 
          nationalId: b.nationalId, 
          phone: b.phone, 
          address: b.address, 
          birthDate: b.birthDate || '',
          regionId: b.regionId || '',
          status: b.status, 
          familyId: b.familyId || '' 
        });
        setEditId(id);
      }
    } else {
      setFormData(initialForm);
      setEditId(null);
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    if (!validate()) return;

    let updatedList: Beneficiary[] = [];
    if (editId) {
      updatedList = beneficiaries.map(b => b.id === editId ? { ...b, ...formData } : b);
      addLog(user, 'تعديل', 'مستفيد', editId);
    } else {
      const newId = Math.random().toString(36).substring(2, 11);
      const newB: Beneficiary = { 
        ...formData, 
        id: newId, 
        branchId: user.branchId, 
        type: modalType, 
        createdAt: new Date().toISOString() 
      };
      updatedList = [...beneficiaries, newB];
      addLog(user, 'إضافة', modalType, newId);
    }
    setBeneficiaries(updatedList);
    setIsModalOpen(false);
  };

  const calculateAge = (dob: string) => {
    if (!dob) return '-';
    const birth = new Date(dob);
    const today = new Date();
    let age = today.getFullYear() - birth.getFullYear();
    const monthDiff = today.getMonth() - birth.getMonth();
    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birth.getDate())) {
        age--;
    }
    return age;
  };

  const branchRegions = regions.filter(r => isAdmin || r.branchId === user.branchId);
  const familyHeads = beneficiaries.filter(b => b.type === BeneficiaryType.FAMILY_HEAD && (isAdmin || b.branchId === user.branchId));

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">إدارة المستفيدين</h1>
          <p className="text-gray-500">الأرشفة الرقمية المتطورة للجمعية</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <button onClick={() => setIsTreeView(!isTreeView)} className="bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-gray-50 font-bold transition">
            {isTreeView ? <LayoutList size={18} /> : <Network size={18} />}
            <span>{isTreeView ? 'قائمة' : 'عرض شجري'}</span>
          </button>
          <button onClick={() => handleOpenModal(BeneficiaryType.INDIVIDUAL)} className="bg-emerald-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-emerald-700 shadow-sm font-bold">
            <UserIcon size={18} /> فرد
          </button>
          <button onClick={() => handleOpenModal(BeneficiaryType.FAMILY_HEAD)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm font-bold">
            <UsersIcon size={18} /> أسرة
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50">
          <div className="relative max-w-md">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="ابحث بالاسم أو الرقم القومي..." 
              className="w-full pr-10 pl-4 py-2 rounded-lg border border-gray-200 focus:ring-2 focus:ring-emerald-500 text-sm" 
              value={searchTerm} 
              onChange={(e) => setSearchTerm(e.target.value)} 
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          {isTreeView ? (
            <div className="p-4 space-y-4">
              {treeData.map(node => (
                <div key={node.id} className="border border-gray-100 rounded-xl overflow-hidden shadow-sm bg-white">
                  <div className="bg-gray-50 p-4 flex items-center justify-between border-b border-gray-100">
                    <div className="flex items-center gap-4">
                      <div>
                        <p className="font-bold text-gray-800">{node.name} <span className="text-xs font-normal text-gray-500 bg-indigo-50 px-2 rounded">{node.type}</span></p>
                        <p className="text-xs text-gray-500 flex items-center gap-2 mt-1">
                          <MapPin size={12} className="text-emerald-500" />
                          {regions.find(r => r.id === node.regionId)?.name || 'غير محدد'} | 
                          <Calendar size={12} className="text-indigo-500 mr-1" />
                          العمر: {calculateAge(node.birthDate)}
                        </p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                       <button onClick={() => handleOpenModal(node.type, node.id)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"><Edit3 size={16} /></button>
                       <button onClick={() => { if(confirm('حذف؟')) setBeneficiaries(beneficiaries.filter(x => x.id !== node.id)) }} className="p-1.5 text-red-600 hover:bg-red-50 rounded"><Trash2 size={16} /></button>
                    </div>
                  </div>
                  {node.members.length > 0 && (
                     <div className="p-4 bg-white space-y-2">
                       {node.members.map(m => (
                         <div key={m.id} className="flex items-center justify-between text-sm bg-gray-50 p-2 rounded-lg border border-gray-100">
                           <span className="font-medium text-gray-700">{m.name}</span>
                           <span className="text-gray-400 text-xs">العمر: {calculateAge(m.birthDate)}</span>
                           <div className="flex gap-2">
                             <button onClick={() => handleOpenModal(m.type, m.id)} className="text-blue-600"><Edit3 size={14} /></button>
                             <button onClick={() => { if(confirm('حذف؟')) setBeneficiaries(beneficiaries.filter(x => x.id !== m.id)) }} className="text-red-600"><Trash2 size={14} /></button>
                           </div>
                         </div>
                       ))}
                     </div>
                  )}
                  {node.type === BeneficiaryType.FAMILY_HEAD && (
                    <div className="bg-gray-50 p-2 text-center border-t border-gray-100">
                      <button onClick={() => { setFormData({ ...initialForm, familyId: node.id }); handleOpenModal(BeneficiaryType.FAMILY_MEMBER); }} className="text-indigo-600 text-xs font-bold flex items-center justify-center gap-1">
                        <Plus size={14} /> إضافة فرد للأسرة
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          ) : (
            <table className="w-full text-right">
              <thead className="bg-gray-50 border-b border-gray-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase">المستفيد</th>
