            <UserIcon size={18} /> فرد
          </button>
          <button onClick={() => handleOpenModal(BeneficiaryType.FAMILY_HEAD)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 shadow-sm font-bold">
            <UsersIcon size={18} /> أسرة
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50">
          <div className="relative max-w-md">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="ابحث بالاسم أو الرقم القومي..." 
              className="w-full pr-10 pl-4 py-2 rounded-lg border border-gray-200 focus:ring-2 focus:ring-emerald-500 text-sm" 
              value={searchTerm} 
              onChange={(e) => setSearchTerm(e.target.value)} 
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          {isTreeView ? (
            <div className="p-4 space-y-4">
              {treeData.map(node => (
                <div key={node.id} className="border border-gray-100 rounded-xl overflow-hidden shadow-sm bg-white">
                  <div className="bg-gray-50 p-4 flex items-center justify-between border-b border-gray-100">
                    <div className="flex items-center gap-4">
                      <div>
                        <p className="font-bold text-gray-800">{node.name} <span className="text-xs font-normal text-gray-500 bg-indigo-50 px-2 rounded">{node.type}</span></p>
                        <p className="text-xs text-gray-500 flex items-center gap-2 mt-1">
                          <MapPin size={12} className="text-emerald-500" />
                          {regions.find(r => r.id === node.regionId)?.name || 'غير محدد'} | 
                          <Calendar size={12} className="text-indigo-500 mr-1" />
                          العمر: {calculateAge(node.birthDate)}
                        </p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                       <button onClick={() => handleOpenModal(node.type, node.id)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"><Edit3 size={16} /></button>
                       <button onClick={() => { if(confirm('حذف؟')) setBeneficiaries(beneficiaries.filter(x => x.id !== node.id)) }} className="p-1.5 text-red-600 hover:bg-red-50 rounded"><Trash2 size={16} /></button>
                    </div>
                  </div>
                  {node.members.length > 0 && (
                     <div className="p-4 bg-white space-y-2">
                       {node.members.map(m => (
                         <div key={m.id} className="flex items-center justify-between text-sm bg-gray-50 p-2 rounded-lg border border-gray-100">
                           <span className="font-medium text-gray-700">{m.name}</span>
                           <span className="text-gray-400 text-xs">العمر: {calculateAge(m.birthDate)}</span>
                           <div className="flex gap-2">
                             <button onClick={() => handleOpenModal(m.type, m.id)} className="text-blue-600"><Edit3 size={14} /></button>
                             <button onClick={() => { if(confirm('حذف؟')) setBeneficiaries(beneficiaries.filter(x => x.id !== m.id)) }} className="text-red-600"><Trash2 size={14} /></button>
