            <div className="flex-1 overflow-y-auto p-6 space-y-4">
              {modalType === BeneficiaryType.FAMILY_MEMBER && (
                <div>
                   <label className="block text-sm font-bold text-gray-700 mb-1">رب الأسرة</label>
                   <select 
                     className="w-full px-4 py-2.5 border rounded-xl bg-white outline-none focus:ring-2 focus:ring-emerald-500"
