          <UserPlus size={18} />
          <span>إضافة مستخدم</span>
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-gray-50 text-gray-500 text-xs font-bold uppercase border-b border-gray-100">
                <th className="px-6 py-4 text-right">الاسم</th>
                <th className="px-6 py-4 text-right">اسم المستخدم</th>
                <th className="px-6 py-4 text-right">الدور</th>
                <th className="px-6 py-4 text-right">الفرع</th>
                <th className="px-6 py-4 text-right">الإجراءات</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {store.users.map(u => (
                <tr key={u.id} className="hover:bg-gray-50 transition">
                  <td className="px-6 py-4 font-bold whitespace-nowrap">{u.name}</td>
                  <td className="px-6 py-4 text-sm text-gray-600 whitespace-nowrap">{u.username}</td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                      u.role === Role.ADMIN ? 'bg-purple-100 text-purple-700' :
                      u.role === Role.MANAGER ? 'bg-orange-100 text-orange-700' : 'bg-blue-100 text-blue-700'
                    }`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-600 whitespace-nowrap">{u.branchId}</td>
                  <td className="px-6 py-4 flex gap-2 whitespace-nowrap">
                    <button onClick={() => handleOpenModal(u.id)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"><Edit3 size={16} /></button>
                    <button onClick={() => handleDelete(u.id)} className="p-1.5 text-red-600 hover:bg-red-50 rounded"><Trash2 size={16} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md flex flex-col max-h-[90vh] overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
              <h3 className="text-xl font-bold text-gray-800">{editId ? 'تعديل' : 'إضافة'} مستخدم</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 transition p-1 rounded-full hover:bg-gray-100">
                <X size={20} />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-6 space-y-4">
              <div className="space-y-1">
                <label className="block text-sm font-bold text-gray-700">الاسم</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-2.5 border border-gray-300 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:outline-none transition-all"
                  placeholder="أدخل اسم الموظف"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                />
              </div>
              <div className="space-y-1">
                <label className="block text-sm font-bold text-gray-700">اسم المستخدم</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-2.5 border border-gray-300 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:outline-none transition-all"
                  placeholder="Username"
                  value={formData.username}
                  onChange={(e) => setFormData({ ...formData, username: e.target.value })}
                />
              </div>
              <div className="space-y-1">
                <label className="block text-sm font-bold text-gray-700">الدور الصلاحية</label>
                <select 
                  className="w-full px-4 py-2.5 border border-gray-300 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:outline-none transition-all bg-white"
                  value={formData.role}
                  onChange={(e) => setFormData({ ...formData, role: e.target.value as Role })}
                >
                  <option value={Role.ADMIN}>{Role.ADMIN}</option>
                  <option value={Role.MANAGER}>{Role.MANAGER}</option>
                  <option value={Role.STAFF}>{Role.STAFF}</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="block text-sm font-bold text-gray-700">الفرع المرتبط</label>
                <select 
                  className="w-full px-4 py-2.5 border border-gray-300 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:outline-none transition-all bg-white"
                  value={formData.branchId}
                  onChange={(e) => setFormData({ ...formData, branchId: e.target.value })}
                >
                  {store.branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                </select>
              </div>
            </div>
            <div className="p-6 bg-gray-50 border-t border-gray-100 flex gap-3">
              <button onClick={() => setIsModalOpen(false)} className="flex-1 px-6 py-2.5 border border-gray-300 rounded-xl text-gray-600 hover:bg-white transition font-bold">إلغاء</button>
              <button onClick={handleSave} className="flex-1 px-6 py-2.5 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition font-bold shadow-lg shadow-emerald-600/20">حفظ</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Users;

